use alloc::alloc::handle_alloc_error;
use core::{
    alloc::Layout,
    cmp, fmt,
    marker::PhantomData,
    mem,
    ops::{Bound, Deref, RangeBounds},
    ptr,
    ptr::NonNull,
    sync::atomic::{AtomicUsize, Ordering, fence},
