**操作步骤**（在你的工程里新建一个示例或 test，例如 `examples/gc_observe.rs`，依赖 `crossbeam-skiplist` 与 `std::sync::Arc`）：

```rust
// 示例代码：观察引用计数对节点回收的推迟作用
use crossbeam_skiplist::SkipMap;
use std::sync::Arc;
use std::thread;

fn main() {
    // 用 Arc 包装 value，便于从外部观察「节点是否已被析构」
    let val = Arc::new(100u64);
    let map = SkipMap::new();
    map.insert(1u64, val.clone());
    // 此时 Arc 强引用计数 = 2（val 一份，map 内部节点一份）

    // 线程 A：拿到 Entry 句柄并长期持有（持有期间引用计数 > 0）
    let map_a = map.clone(); // SkipMap: Clone（内部 Arc 共享）
    let handle = thread::spawn(move || {
        let entry = map_a.get(&1).expect("key 1 must exist at first");
        // 模拟 A 慢慢用这个句柄……
        thread::sleep(std::time::Duration::from_millis(200));
        // 关键断言：即便 B 已经删掉了 key=1，A 的句柄仍能安全读到旧值
        assert_eq!(*entry.value(), 100);
        println!("A: 仍能安全读到已删除节点的旧值 = {}", entry.value());
        // entry 在此 drop → 引用计数归零 → 节点被投递进垃圾袋
    });

    // 线程 B：在 A 持有句柄期间删除 key=1
    let map_b = map.clone();
    thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(50));
        let removed = map_b.remove(&1);
        println!("B: remove 返回了一个 Entry 句柄？ {}", removed.is_some());
        // remove 返回的 Entry 也会持有一份引用；它 drop 后引用计数再减一
    }).join().unwrap();

    handle.join().unwrap();

    // 到这里 A 的句柄、B 返回的句柄都已 drop；但节点何时真正析构取决于 epoch 何时推进。
    // 真正回收发生在线程下次 pin/unpin 推进全局 epoch 之后。
    println!("外部 Arc 强引用计数 = {}", Arc::strong_count(&val)); // 仍可能 > 1
    println!("（节点真正析构的时机由 epoch 推进决定，不保证在此时已完成）");
}
```

